var epsilons = new[] { 0.01, 0.05, 0.1, 0.2, 0.3, 0.5 };
const int N = 10;
var sb = new StringBuilder();
sb.AppendLine("Impact de epsilon sur les gains (n_markets=10, 5000 sims/point)");
