{
    double closed = R / (1 - d);
    double approx = FluxGeom(R, d);
    Console.WriteLine($"delta={d,-5:F2} : formule g/(1-d)={closed,10:F4} | somme tronquee={approx,10:F4}");
}
Console.WriteLine();
