// Nim-sum : XOR des tailles de tas (Bouton's theorem).
static int NimSum(params int[] heaps)
{
    int r = 0;
    foreach (int h in heaps) r ^= h;
    return r;
}

static char NimPositionType(params int[] heaps) => NimSum(heaps) == 0 ? 'P' : 'N';

