    $"Nouvelle position: [{string.Join(", ", newHeaps)}]  Nim-sum: {NimSum(newHeaps)}".Display();
}

// mex : plus petit entier >= 0 absent de l'ensemble.
static int Mex(IEnumerable<int> s)
{
    var set = new HashSet<int>(s);
    int n = 0;
    while (set.Contains(n)) n++;
    return n;
}

