string Row(string name, Func<List<List<string>>, List<string>> rule)
{
    int par = ParetoViolations(rule, alts3, nVot);
    var (viia, _) = IiaViolations(rule, alts3, nVot);
    int dic = FindDictator(rule, alts3, nVot);
