    string iiaTxt = viia == 0 ? "OK" : ("ECHEC x" + viia);
    string dicTxt = dic < 0 ? "OK" : ("Dict(V" + dic + ")");
    return string.Format("{0,-13} {1,-10} {2,-22} {3,-15}", name, paretoTxt, iiaTxt, dicTxt);
}

